import java.util.*;

class AllOne {

    private Map<String, Integer> keyCountMap;
    private Map<Integer, Set<String>> countKeyMap;
    private int minCount;
    private int maxCount;

    public AllOne() {
        keyCountMap = new HashMap<>();
        countKeyMap = new HashMap<>();
        minCount = 0;
        maxCount = 0;
    }

    public void inc(String key) {
        int count = keyCountMap.getOrDefault(key, 0) + 1;
        keyCountMap.put(key, count);

        countKeyMap.computeIfAbsent(count - 1, k -> new HashSet<>()).remove(key);
        if (countKeyMap.get(count - 1).isEmpty()) {
            countKeyMap.remove(count - 1);
            if (minCount == count - 1) {
                minCount = countKeyMap.keySet().stream().min(Integer::compare).orElse(0);
            }
        }

        countKeyMap.computeIfAbsent(count, k -> new HashSet<>()).add(key);
        if (maxCount == 0 || count > maxCount) {
            maxCount = count;
        }
    }

    public void dec(String key) {
        int count = keyCountMap.get(key) - 1;
        keyCountMap.put(key, count);

        countKeyMap.get(count + 1).remove(key);
        if (countKeyMap.get(count + 1).isEmpty()) {
            countKeyMap.remove(count + 1);
            if (maxCount == count + 1) {
                maxCount = countKeyMap.keySet().stream().max(Integer::compare).orElse(0);
            }
        }

        countKeyMap.computeIfAbsent(count, k -> new HashSet<>()).add(key);
        if (minCount == 0 || count < minCount) {
            minCount = count;
        }
    }

    public String getMaxKey() {
        if (maxCount == 0) {
            return "";
        }
        return countKeyMap.get(maxCount).iterator().next();
    }

    public String getMinKey() {
        if (minCount == 0) {
            return "";
        }
        return countKeyMap.get(minCount).iterator().next();
    }
}
